// Captura os dados que vieram da VAPI
const dados = $('Webhook Google_agenda').item.json.body.message.toolCalls[0].function;
let args = dados.arguments;

if (typeof args === 'string') {
    args = JSON.parse(args);
}

// Pega a data pura enviada pela VAPI (Ex: "2026-05-19")
const dataPura = args.data_consulta.split('T')[0];

// Define o início e o fim do dia exatamente no mesmo dia, sem mexer em fusos que alterem o mês
args.timeMin = dataPura + "T00:00:00-03:00";
args.timeMax = dataPura + "T23:59:59-03:00";

return { json: args };

const raw = $input.item.json.body.message.toolCalls[0].function.arguments;
const args = typeof raw === 'string' ? JSON.parse(raw) : raw;

return {
  data_selecionada: args.data_selecionada,
  primeiro_nome: args.first_name,
  email: args.email,
  resumo_conversa: args.resumo_conversa,
  telefone: args.telefone
};
